// Secure player stats - never use public variables for sensitive game state
public class PlayerStats
{
    private float _health;
    private float _maxHealth;
    private int _currency;
    private int _level;
    private string _integrityHash;
    private readonly string _salt;

    public float Health => _health;
    public float MaxHealth => _maxHealth;
    public int Currency => _currency;
    public int Level => _level;

    public PlayerStats(float maxHealth, int startingCurrency, int level)
    {
        _salt = Guid.NewGuid().ToString();
        _maxHealth = maxHealth;
        _health = maxHealth;
        _currency = startingCurrency;
        _level = level;
        UpdateIntegrityHash();
    }

    private string ComputeHash()
    {
        string data = $"{_health}:{_maxHealth}:{_currency}:{_level}:{_salt}";
        using (SHA256 sha256 = SHA256.Create())
        {
            byte[] bytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(data));
            return Convert.ToBase64String(bytes);
        }
    }

    private void UpdateIntegrityHash()
    {
        _integrityHash = ComputeHash();
    }

    public bool ValidateIntegrity()
    {
        return _integrityHash == ComputeHash();
    }

    public bool ApplyDamage(float damage)
    {
        if (!ValidateIntegrity())
        {
            Debug.LogError("Data integrity violation detected!");
            return false;
        }

        if (damage < 0)
        {
            Debug.LogWarning("Negative damage rejected.");
            return false;
        }

        _health = Mathf.Max(0f, _health - damage);
        UpdateIntegrityHash();
        return true;
    }

    public bool Heal(float amount)
    {
        if (!ValidateIntegrity())
        {
            Debug.LogError("Data integrity violation detected!");
            return false;
        }

        if (amount < 0)
        {
            Debug.LogWarning("Negative heal rejected.");
            return false;
        }

        _health = Mathf.Min(_maxHealth, _health + amount);
        UpdateIntegrityHash();
        return true;
    }

    public bool SpendCurrency(int amount)
    {
        if (!ValidateIntegrity())
        {
            Debug.LogError("Data integrity violation detected!");
            return false;
        }

        if (amount <= 0)
        {
            Debug.LogWarning("Invalid spend amount.");
            return false;
        }

        if (_currency < amount)
        {
            Debug.LogWarning("Insufficient currency.");
            return false;
        }

        _currency -= amount;
        UpdateIntegrityHash();
        return true;
    }

    public bool AddCurrency(int amount)
    {
        if (!ValidateIntegrity())
        {
            Debug.LogError("Data integrity violation detected!");
            return false;
        }

        if (amount <= 0)
        {
            Debug.LogWarning("Invalid add amount.");
            return false;
        }

        // Overflow check
        if (_currency > int.MaxValue - amount)
        {
            Debug.LogWarning("Currency overflow prevented.");
            return false;
        }

        _currency += amount;
        UpdateIntegrityHash();
        return true;
    }

    public bool SetLevel(int newLevel)
    {
        if (!ValidateIntegrity())
        {
            Debug.LogError("Data integrity violation detected!");
            return false;
        }

        if (newLevel < 1 || newLevel > 100)
        {
            Debug.LogWarning("Invalid level.");
            return false;
        }

        _level = newLevel;
        UpdateIntegrityHash();
        return true;
    }
}

