// Server-authoritative shop catalog - prices should NOT be calculated on client
public class ShopCatalog
{
    private readonly Dictionary<string, ShopItemDefinition> _items;

    public ShopCatalog()
    {
        _items = new Dictionary<string, ShopItemDefinition>();
    }

    public void RegisterItem(ShopItemDefinition item)
    {
        if (item == null || string.IsNullOrEmpty(item.ItemId))
            return;

        _items[item.ItemId] = item;
    }

    public ShopItemDefinition GetItem(string itemId)
    {
        if (string.IsNullOrEmpty(itemId))
            return null;

        _items.TryGetValue(itemId, out ShopItemDefinition item);
        return item;
    }

    // Price is determined by the catalog, not by client input
    public int GetPrice(string itemId)
    {
        var item = GetItem(itemId);
        return item?.BasePrice ?? -1;
    }

    public IReadOnlyDictionary<string, ShopItemDefinition> GetAllItems()
    {
        return _items;
    }
}

// Damage calculator with server-authoritative values
public class DamageCalculator
{
    // Damage formulas use server-defined constants, not client-modifiable values
    private const float BASE_DAMAGE_MULTIPLIER = 1.0f;
    private const float LEVEL_DAMAGE_SCALE = 0.1f;
    private const float MAX_DAMAGE_CAP = 9999f;
    private const float MIN_DAMAGE = 0f;

    // All parameters are validated and clamped
    public static float CalculateDamage(float baseDamage, int attackerLevel, float defenseRating, float damageBonus)
    {
        // Validate inputs
        if (baseDamage < 0) baseDamage = 0;
        if (attackerLevel < 1) attackerLevel = 1;
        if (attackerLevel > 100) attackerLevel = 100;
        if (defenseRating < 0) defenseRating = 0;
        if (damageBonus < 0) damageBonus = 0;

        float levelMultiplier = BASE_DAMAGE_MULTIPLIER + (attackerLevel * LEVEL_DAMAGE_SCALE);
        float rawDamage = (baseDamage + damageBonus) * levelMultiplier;
        float mitigatedDamage = rawDamage * (100f / (100f + defenseRating));

        // Clamp to prevent exploits
        return Mathf.Clamp(mitigatedDamage, MIN_DAMAGE, MAX_DAMAGE_CAP);
    }
}

