// Secure save/load with encryption
public static class SecureSaveSystem
{
    // In production, use a proper key management system
    // This key should be obfuscated and not stored in plain text
    private static readonly byte[] _encryptionKey = new byte[32];
    private static readonly byte[] _iv = new byte[16];
    private static bool _initialized = false;

    private static void EnsureInitialized()
    {
        if (!_initialized)
        {
            // Derive key from device-specific info (better than hardcoded)
            string deviceSeed = SystemInfo.deviceUniqueIdentifier + "GameSalt2024";
            using (var deriveBytes = new Rfc2898DeriveBytes(deviceSeed, Encoding.UTF8.GetBytes("SecureSalt"), 10000))
            {
                Array.Copy(deriveBytes.GetBytes(32), _encryptionKey, 32);
                Array.Copy(deriveBytes.GetBytes(16), _iv, 16);
            }
            _initialized = true;
        }
    }

    public static string Encrypt(string plainText)
    {
        EnsureInitialized();
        using (Aes aes = Aes.Create())
        {
            aes.Key = _encryptionKey;
            aes.IV = _iv;

            ICryptoTransform encryptor = aes.CreateEncryptor(aes.Key, aes.IV);
            byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
            byte[] encryptedBytes = encryptor.TransformFinalBlock(plainBytes, 0, plainBytes.Length);
            return Convert.ToBase64String(encryptedBytes);
        }
    }

    public static string Decrypt(string cipherText)
    {
        EnsureInitialized();
        try
        {
            using (Aes aes = Aes.Create())
            {
                aes.Key = _encryptionKey;
                aes.IV = _iv;

                ICryptoTransform decryptor = aes.CreateDecryptor(aes.Key, aes.IV);
                byte[] cipherBytes = Convert.FromBase64String(cipherText);
                byte[] plainBytes = decryptor.TransformFinalBlock(cipherBytes, 0, cipherBytes.Length);
                return Encoding.UTF8.GetString(plainBytes);
            }
        }
        catch (Exception e)
        {
            Debug.LogError($"Decryption failed - possible tampering: {e.Message}");
            return null;
        }
    }

    public static void SavePlayerData(string key, string jsonData)
    {
        string encrypted = Encrypt(jsonData);
        string hmac = ComputeHMAC(encrypted);
        PlayerPrefs.SetString(key, encrypted);
        PlayerPrefs.SetString(key + "_hmac", hmac);
        PlayerPrefs.Save();
    }

    public static string LoadPlayerData(string key)
    {
        if (!PlayerPrefs.HasKey(key) || !PlayerPrefs.HasKey(key + "_hmac"))
            return null;

        string encrypted = PlayerPrefs.GetString(key);
        string storedHmac = PlayerPrefs.GetString(key + "_hmac");
        string computedHmac = ComputeHMAC(encrypted);

        if (storedHmac != computedHmac)
        {
            Debug.LogError("Save data integrity check failed - possible tampering!");
            return null;
        }

        return Decrypt(encrypted);
    }

    private static string ComputeHMAC(string data)
    {
        EnsureInitialized();
        using (HMACSHA256 hmac = new HMACSHA256(_encryptionKey))
        {
            byte[] hash = hmac.ComputeHash(Encoding.UTF8.GetBytes(data));
            return Convert.ToBase64String(hash);
        }
    }
}

