    private void LoadOrCreatePlayerStats()
    {
        string savedData = SecureSaveSystem.LoadPlayerData("player_save");

        if (savedData != null)
        {
            try
            {
                PlayerSaveData save = JsonUtility.FromJson<PlayerSaveData>(savedData);
                if (save != null && ValidateSaveData(save))
                {
                    _playerStats = new PlayerStats(save.maxHealth, save.currency, save.level);
                    float damageToApply = save.maxHealth - save.health;
                    if (damageToApply > 0)
                        _playerStats.ApplyDamage(damageToApply);

                    if (save.purchaseCounts != null)
                        _purchaseCounts = new Dictionary<string, int>(save.purchaseCounts);

                    Debug.Log("Player data loaded successfully.");
                    return;
                }
            }
            catch (Exception e)
            {
                Debug.LogError($"Failed to load save data: {e.Message}");
