    private bool ValidateSaveData(PlayerSaveData save)
    {
        if (save.maxHealth < 100f || save.maxHealth > 10000f) return false;
        if (save.health < 0 || save.health > save.maxHealth) return false;
        if (save.currency < 0 || save.currency > 999999999) return false;
        if (save.level < 1 || save.level > 100) return false;
        return true;
    }

    public void SaveGame()
    {
        if (_playerStats == null || !_playerStats.ValidateIntegrity())
        {
            Debug.LogError("Cannot save - data integrity violation!");
            return;
