    // Damage system - all calculations use validated, server-defined values
    public void DamagePlayer(float baseDamage, int enemyLevel)
    {
        if (_playerStats == null) return;

        if (!_playerStats.ValidateIntegrity())
        {
            Debug.LogError("Player data integrity violation! Resetting.");
            HandleIntegrityViolation();
            return;
        }

        // Validate enemy parameters
        baseDamage = Mathf.Clamp(baseDamage, 0f, 1000f);
        enemyLevel = Mathf.Clamp(enemyLevel, 1, 100);

        float damage = DamageCalculator.CalculateDamage(baseDamage, enemyLevel, 0f, 0f);

        if (_playerStats.ApplyDamage(damage))
        {
            OnHealthChanged?.Invoke(_playerStats.Health, _playerStats.MaxHealth);
            Debug.Log($"Player took {damage:F1} damage. Health: {_playerStats.Health:F1}/{_playerStats.MaxHealth:F1}");

            if (_playerStats.Health <= 0)
            {
                HandlePlayerDeath();
            }
        }
    }

    public float CalculatePlayerAttackDamage(float baseWeaponDamage, float targetDefense)
    {
        if (_playerStats == null) return 0f;

        baseWeaponDamage = Mathf.Clamp(baseWeaponDamage, 0f, 500f);
        targetDefense = Mathf.Clamp(targetDefense, 0f, 1000f);

        return DamageCalculator.CalculateDamage(
            baseWeaponDamage,
            _playerStats.Level,
            targetDefense,
            _playerDamageBonus
        );
    }

    // Shop system - prices come from catalog, not client
    public bool PurchaseItem(string itemId)
    {
        if (_playerStats == null || string.IsNullOrEmpty(itemId))
        {
            OnPurchaseResult?.Invoke(itemId, false);
            return false;
        }

        if (!_playerStats.ValidateIntegrity())
        {
            Debug.LogError("Data integrity violation during purchase!");
            HandleIntegrityViolation();
            OnPurchaseResult?.Invoke(itemId, false);
            return false;
        }

        ShopItemDefinition item = _shopCatalog.GetItem(itemId);
        if (item == null)
        {
            Debug.LogWarning($"Item not found: {itemId}");
            OnPurchaseResult?.Invoke(itemId, false);
            return false;
        }

        // Check purchase limits
        _purchaseCounts.TryGetValue(itemId, out int currentCount);
        if (currentCount >= item.MaxPurchaseCount)
        {
            Debug.LogWarning($"Purchase limit reached for {item.DisplayName}");
            OnPurchaseResult?.Invoke(itemId, false);
            return false;
        }

        // Price comes from the catalog, NOT from any client-supplied value
        int price = item.BasePrice;

        if (_playerStats.Currency < price)
        {
            Debug.LogWarning($"Insufficient currency for {item.DisplayName}. Need {price}, have {_playerStats.Currency}");
            OnPurchaseResult?.Invoke(itemId, false);
            return false;
        }

        // Process purchase
        if (!_playerStats.SpendCurrency(price))
        {
            OnPurchaseResult?.Invoke(itemId, false);
            return false;
        }

        // Apply item effects
        ApplyItemEffects(item);

        // Record purchase
        _purchaseCounts[itemId] = currentCount + 1;
        _purchaseHistory.Add(new PurchaseRecord(itemId, price));

        OnCurrencyChanged?.Invoke(_playerStats.Currency);
        OnPurchaseResult?.Invoke(itemId, true);

        Debug.Log($"Purchased {item.DisplayName} for {price} currency. Remaining: {_playerStats.Currency}");

        // Auto-save after purchase
        SaveGame();

        return true;
    }

    private void ApplyItemEffects(ShopItemDefinition item)
    {
        if (item.HealAmount > 0)
        {
            _playerStats.Heal(item.HealAmount);
            OnHealthChanged?.Invoke(_playerStats.Health, _playerStats.MaxHealth);
        }

        if (item.DamageBonus > 0)
        {
            _playerDamageBonus += item.DamageBonus;
        }
    }

